# Shapes module - concrete implementations
from geometry import Shape, ShapeColor, Point, IDrawable, IMeasurable

class Circle(Shape, IDrawable, IMeasurable):
    _center: Point
    _radius: float

    def __init__(self, center: Point, radius: float, color: ShapeColor):
        super().__init__(color)
        self._center = center
        self._radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self._radius * self._radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self._radius

    @override
    def describe(self) -> str:
        return f"Circle with radius {self._radius:.2f} at ({self._center.x:.1f}, {self._center.y:.1f})"

    def draw(self) -> str:
        return f"Drawing circle: {self.describe()}"

    def scale(self, factor: float) -> Circle:
        return Circle(self._center, self._radius * factor, self._color)

@abstract
class Polygon(Shape):
    _vertices: list[Point]

    def __init__(self, color: ShapeColor, vertices: list[Point]):
        super().__init__(color)
        self._vertices = vertices.copy()

    @override
    def describe(self) -> str:
        return f"Polygon with {len(self._vertices)} vertices"

class Triangle(Polygon, IMeasurable):
    def __init__(self, p1: Point, p2: Point, p3: Point, color: ShapeColor):
        vertices: list[Point] = [p1, p2, p3]
        super().__init__(color, vertices)

    @override
    def area(self) -> float:
        p1: Point = self._vertices[0]
        p2: Point = self._vertices[1]
        p3: Point = self._vertices[2]
        return p1.x * (p2.y - p3.y) + p2.x * (p3.y - p1.y) + p3.x * (p1.y - p2.y)

    @override
    def perimeter(self) -> float:
        p1: Point = self._vertices[0]
        p2: Point = self._vertices[1]
        p3: Point = self._vertices[2]
        d1: float = p1.distance_to(p2)
        d2: float = p2.distance_to(p3)
        d3: float = p3.distance_to(p1)
        return d1 + d2 + d3

