# Utilities module - helper functions
from geometry import ShapeColor, Point, IDrawable

def create_random_color(seed: int) -> ShapeColor:
    if seed % 4 == 0:
        return ShapeColor.RED
    elif seed % 4 == 1:
        return ShapeColor.BLUE
    elif seed % 4 == 2:
        return ShapeColor.GREEN
    else:
        return ShapeColor.YELLOW

class ShapeStatistics:
    @static
    total_shapes_created: int = 0

    @staticmethod
    def increment_count():
        ShapeStatistics.total_shapes_created += 1

    @staticmethod
    def get_count() -> int:
        return ShapeStatistics.total_shapes_created

def process_drawables(items: list[IDrawable]) -> list[str]:
    results: list[str] = []
    for item in items:
        results.append(item.draw())
    return results
